// ── Apply translations ──────────────────────────────────────────

for (const [locale, map] of Object.entries(translations)) {
  const file = join(LOCALES_DIR, `${locale}.ts`);
  let content = readFileSync(file, 'utf-8');
  let count = 0;

  for (const [eng, native] of Object.entries(map)) {
    if (content.includes(eng)) {
      content = content.replace(eng, native);
      count++;
    }
  }

  writeFileSync(file, content, 'utf-8');
  console.log(`✓ ${locale}.ts: ${count} strings translated`);
}

console.log('\nDone! All locale files translated.');
